8227	\begin{lemma}[The category of schemes is finitary extensive]
8228	  \label{lem:finitaryExtensive_scheme_mathlib}
8229	  \lean{AlgebraicGeometry.instFinitaryExtensiveScheme}
8230	  \mathlibok
8231	  \textit{Provided by Mathlib.}
8232	  The category \(\operatorname{Scheme}\) is finitary extensive: finite coproducts are disjoint
8233	  and universal (stable under pullback). In particular it is finitary pre-extensive and has
8234	  finite coproducts and pullbacks, so the abstract distributivity of
8235	  Lemma~\ref{lem:isIso_sigmaDesc_map_mathlib} applies at \(\mathcal{C} = \operatorname{Scheme}\).
8236	\end{lemma}
8237	
8238	\begin{lemma}[Coproducts distribute over the binary fibre product]
8239	  \label{lem:isIso_sigmaDesc_map_mathlib}
8240	  \lean{CategoryTheory.FinitaryPreExtensive.isIso_sigmaDesc_map}
8241	  \mathlibok
8242	  \textit{Provided by Mathlib.}
8243	  In a finitary pre-extensive category with pullbacks, for finite index types \(\iota, \iota'\),
8244	  a base \(S\), and families \((X_i \to S)_i\), \((Y_j \to S)_j\), the canonical map
8245	  \(\coprod_{(i,j)} (X_i \times_S Y_j) \to (\coprod_i X_i) \times_S (\coprod_j Y_j)\),
8246	  \(\operatorname{Sigma.desc}\) of the pullback maps, is an isomorphism. Taking one family to be a
8247	  singleton gives the one-sided distributivity
8248	  \((\coprod_i X_i) \times_S Y \cong \coprod_i (X_i \times_S Y)\) used in the induction of
8249	  Lemma~\ref{lem:coproduct_distrib_fibrePower}.
8250	\end{lemma}
8251	
8252	\begin{lemma}[Pullback of two open immersions is the intersection open]
8253	  \label{lem:isPullback_opens_inf_mathlib}
8254	  \lean{AlgebraicGeometry.isPullback_opens_inf}
8255	  \mathlibok
8256	  \textit{Provided by Mathlib.}
8257	  For two opens \(U, V\) of a scheme \(X\), the square with vertex \((U \sqcap V).\mathrm{toScheme}\)
8258	  and the two \(\operatorname{homOfLE}\) inclusions into \(U\) and \(V\) is a pullback of the open
8259	  immersions \(U.\iota, V.\iota\). Equivalently \(\operatorname{pullback} U.\iota\,V.\iota \cong
8260	  (U \sqcap V).\mathrm{toScheme}\): the fibre product of open immersions over \(X\) is the
8261	  intersection of their images.
8262	\end{lemma}
8263	
8264	\begin{lemma}[A wide pullback over a terminal base is the product of its legs]
8265	  \label{lem:widePullbackCone_isLimitOfFan_mathlib}
8266	  \lean{CategoryTheory.Limits.WidePullbackCone.isLimitOfFan}
8267	  \mathlibok
8268	  \textit{Provided by Mathlib.}
8269	  When the base of a wide pullback is a terminal object, a limiting fan of the legs is a limit of
8270	  the wide-pullback diagram. Hence in \(\operatorname{Over} S\) --- where \(\operatorname{Over.mk}
8271	  (\mathrm{id}_S)\) is terminal --- the wide pullback over \(S\) of a family is the product of the
8272	  legs in the slice, which is what lets the fibre power over \(S\) be treated as an iterated
8273	  product in Lemma~\ref{lem:coproduct_distrib_fibrePower}.
8274	\end{lemma}
8275	
8276	\begin{lemma}[The identity arrow is terminal in the slice category]
8277	  \label{lem:over_mkIdTerminal_mathlib}
8278	  \lean{CategoryTheory.Over.mkIdTerminal}
8279	  \mathlibok
8280	  \textit{Provided by Mathlib.}
8281	  For an object \(S\) of a category, \(\operatorname{Over.mk}(\mathrm{id}_S)\) is a terminal object
8282	  of the slice category \(\operatorname{Over} S\). This is what makes the base of a wide pullback
8283	  over \(S\) terminal in the slice, so that
8284	  Lemma~\ref{lem:widePullbackCone_isLimitOfFan_mathlib} exhibits the fibre power over \(S\) as the
8285	  product in \(\operatorname{Over} S\) in Lemma~\ref{lem:widePullback_overX_eq_prod}.
8286	\end{lemma}
8287	
8288	\begin{lemma}[Nested coproducts flatten to a coproduct over pairs]
8289	  \label{lem:sigmaSigmaIso_mathlib}
8290	  \lean{CategoryTheory.Limits.sigmaSigmaIso}
8291	  \mathlibok
8292	  \textit{Provided by Mathlib.}
8293	  For a doubly-indexed family \((Z_{i,j})\), the nested coproduct is the coproduct over pairs:
8294	  \(\coprod_i \coprod_j Z_{i,j} \cong \coprod_{(i,j)} Z_{i,j}\). This collapses the nested
8295	  coproduct produced by one inductive step of the binary distributivity into a single coproduct
8296	  over the multi-indices \(\sigma\) in Lemma~\ref{lem:coproduct_distrib_fibrePower}.
8297	\end{lemma}
